import{c as a,Q as t,j as n,m as i}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"ADR-017 — Paraglide-js for i18n, locale overlay architecture for content","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-017.md","filePath":"adr/ADR-017.md"}'),o={name:"adr/ADR-017.md"};function s(r,e,l,c,d,u){return t(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="adr-017-—-paraglide-js-for-i18n-locale-overlay-architecture-for-content" tabindex="-1">ADR-017 — Paraglide-js for i18n, locale overlay architecture for content <a class="header-anchor" href="#adr-017-—-paraglide-js-for-i18n-locale-overlay-architecture-for-content" aria-label="Permalink to &quot;ADR-017 — Paraglide-js for i18n, locale overlay architecture for content&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 TA anchor · §stack · §contracts</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Orrery targets a global audience. English (US) is the initial locale but the architecture must support translation of both UI chrome and all mission/editorial content. The i18n architecture must not require modifying existing mission JSON files to add a new language.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Two-part i18n architecture:</p><p><strong>1. UI chrome — Paraglide-js.</strong> Compile-time i18n for all UI strings (nav labels, button text, HUD labels, tab names, status badges, error messages). Strings live in <code>src/lib/i18n/en-US.json</code>. Each language adds a new file. Paraglide tree-shakes unused locale strings at build time — no runtime overhead for the active locale.</p><p><strong>2. Mission and editorial content — locale overlay files.</strong> Base mission files (<code>data/missions/mars/curiosity.json</code>) contain only language-neutral data: dates, delta-v, agency, links, orbital elements. Language-specific content lives in separate overlay files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/i18n/en-US/missions/mars/curiosity.json   ← name, description, first, type, events[].note</span></span>
<span class="line"><span>data/i18n/fr/missions/mars/curiosity.json</span></span>
<span class="line"><span>data/i18n/es/missions/mars/curiosity.json</span></span></code></pre></div><p>The data client merges base + locale overlay at fetch time. Missing translations fall back to <code>en-US</code>.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Paraglide is the SvelteKit-native i18n library — it integrates directly with SvelteKit&#39;s routing and compiles translations at build time. The locale overlay architecture keeps base data files clean and language-independent: adding a new language means adding new files, not modifying the 28 existing mission files. A translator can work entirely in <code>data/i18n/[locale]/</code> without touching any JavaScript or base data.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>svelte-i18n</strong> — runtime i18n; larger bundle; less type-safe; rejected.</li><li><strong>Embedded language keys in mission JSON</strong> (<code>&quot;description_en&quot;</code>, <code>&quot;description_fr&quot;</code>) — simpler structure; requires editing all 28 files per new language; rejected.</li><li><strong>Single locale file per language</strong> — one big <code>fr.json</code> with all content; hard to maintain; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: adding a language requires zero code changes; translators work in JSON files; UI strings tree-shaken at build; base mission data is language-independent. Negative: data client merge step adds a small amount of complexity; locale overlay files must be kept in sync with base files when mission data changes.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>src/lib/i18n/</code> for UI strings. <code>data/i18n/[locale]/</code> for content overlays. Data client gains a <code>locale</code> parameter, defaults to <code>en-US</code>, falls back to <code>en-US</code> for missing translations. SvelteKit layout reads locale from URL prefix (<code>/fr/explore</code>) or browser <code>Accept-Language</code> header.</p>`,18)])])}const h=a(o,[["render",s]]);export{g as __pageData,h as default};
